#include <bits/stdc++.h>
using namespace std;

const int N=55;

int n,m,ch,cl,h[N][N],l[N][N],match[N*N];
char s[N][N];
bool vis[N*N];
vector<int> g[N*N];

bool dfs(int x){
    for(int y:g[x])
        if(!vis[y]){
            vis[y]=1;
            if(!match[y] || dfs(match[y])){
                match[y]=x;
                return 1;
            }
        }
    return 0;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%s",s[i]+1);
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            if(s[i][j]=='.')
                continue;
            if(i==1 || s[i-1][j]=='.')
                l[i][j]=++cl;
            else
                l[i][j]=l[i-1][j];
            if(j==1 || s[i][j-1]=='.')
                h[i][j]=++ch;
            else
                h[i][j]=h[i][j-1];
            g[h[i][j]].push_back(l[i][j]);
        }
    }
    int ans=0;
    for(int i=1;i<=ch;i++){
        memset(vis,0,sizeof(vis));
        if(dfs(i))
            ans++;
    }
    printf("%d",ans);
    return 0;
}
